思路：非常典型的 递归回溯 模板题
遍历输入矩阵，找到起点和终点位置。
从起点出发使用 递归回溯 统计可能路径。
递归回溯就是一个模板，可参照下面代码逻辑体会一下。
C++
#include<iostream>
#include<vector>
#include<string>
#include <utility>
#include <sstream>
#include<algorithm>
#include<cmath>
#include<map>
#include<climits>
using namespace std;
int dx[4] = {1, -1, 0, 0};
int dy[4] = {0, 0, 1, -1};
bool visited[15][15];
int sx,sy,ex,ey;
//
递归回溯
int dfs(int x, int y, int n, int m, int k,
vector<vector<int>>& grid) {
//
到达终点
if (x == ex && y
== ey) {
return 1;
}
visited[x][y] = true;
int res = 0;
for (int i = 0; i <
4; i++) {
int nx = x + dx[i];
int ny = y + dy[i];
//
越界
if (nx < 0 || nx >= n || ny < 0 || ny >= m) {
continue;
}
//
重复
if (visited[nx][ny]) {
continue;
}
int diff = grid[nx][ny] - grid[x][y];
if (diff > 0 && diff <= k) {
res += dfs(nx, ny, n, m, k, grid);
}
}
visited[x][y] = false;
//
回溯
return res;
}
int cal(int n, int m, int k,
vector<vector<int>>& grid) {
//
找到终点
/
起点坐标
int minVal = INT_MAX, maxVal =
INT_MIN;
for (int i = 0; i < n; i++)
{
for (int j =0; j < m; j++) {
if (grid[i][j] < minVal) {
minVal = grid[i][j];
sx = i; sy = j;
}
if (grid[i][j] > maxVal) {
maxVal = grid[i][j];
ex = i; ey = j;
}
}
}
return dfs(sx, sy, n, m,
k, grid);
}
int main() {
int n, m, k;
cin >> n >>
m >> k;
vector<vector<int>> grid(n, vector<int>(m));
for (int i = 0; i <
n; i++) {
for (int j = 0; j < m; j++) {
cin >> grid[i][j];
}
}
int res = cal(n, m, k,
grid);
cout << res;
return 0;
}
